// Extract phone number from body.data if it exists
const items = $input.all();

for (let item of items) {
  // Check if phone_number exists in body.data
  if (item.json.body && item.json.body.data && item.json.body.data.phone_number) {
    let phoneNumber = item.json.body.data.phone_number;

    // Remove all non-digit characters
    let digitsOnly = phoneNumber.replace(/\D/g, '');

    // Format to E.164
    if (digitsOnly.length === 10) {
      // Add +1 prefix for 10-digit numbers
      item.json.body.data.phone_number = '+1' + digitsOnly;
    } else if (digitsOnly.length === 11 && digitsOnly.startsWith('1')) {
      // Add + prefix if missing but number starts with 1 and is 11 digits
      item.json.body.data.phone_number = '+' + digitsOnly;
    } else if (digitsOnly.startsWith('1') && digitsOnly.length > 10) {
      // Ensure + prefix for numbers starting with 1
      item.json.body.data.phone_number = '+' + digitsOnly;
    } else {
      // Keep original if it doesn't match expected patterns
      item.json.body.data.phone_number = phoneNumber;
    }
  }
}

return items;

